static string[] SplitBase64IntoSegments(string base64, 
    int maxSegmentLength = 65_536)
{
    int count = (base64.Length + maxSegmentLength - 1) / maxSegmentLength;
    string[] segments = new string[count];

    for (int i = 0; i < count; i++)
    {
        int start = i * maxSegmentLength;
        int len = Math.Min(maxSegmentLength, base64.Length - start);
        segments[i] = base64.Substring(start, len);
    }
    return segments;
}
